+static bool
+tryToSimplifySaturatingMath(IntrinsicInst *II, ConstraintInfo &Info,
+                            SmallVectorImpl<Instruction *> &ToRemove) {
+  auto DoesConditionHold = [](CmpInst::Predicate Pred, Value *A, Value *B,
+                              ConstraintInfo &Info) {
+    auto R = Info.getConstraintForSolving(Pred, A, B);
+    if (R.size() < 2 || !R.isValid(Info))
+      return false;
+
+    auto &CSToUse = Info.getCS(R.IsSigned);
+    return CSToUse.isConditionImplied(R.Coefficients);
+  };
+
+  bool Changed = false;
+  Value *A = II->getArgOperand(0);
+  Value *B = II->getArgOperand(1);
+  Type *Ty = A->getType();
+  switch (II->getIntrinsicID()) {
+  case Intrinsic::usub_sat: {
+    // If A >= B, usub_sat(A, B) == A - B
+    if (DoesConditionHold(CmpInst::ICMP_UGE, A, B, Info)) {
+      IRBuilder<> Builder(II->getParent(), II->getIterator());
+      Value *Sub = Builder.CreateSub(A, B);
+      II->replaceAllUsesWith(Sub);
+      Changed = true;
+    } else if (DoesConditionHold(CmpInst::ICMP_ULT, A, B, Info)) {
+      // If A < B, usub_sat(A, B) == 0
+      II->replaceAllUsesWith(ConstantInt::get(Ty, 0));
